const body = $input.first().json.body;
return [{ json: {
  text: body.text || '',
  chatId: body.chatId,
  username: body.username || 'Cricket Fan'
}}];

const groqRes = $input.first().json;
const prev = $('Build Intent Request').first().json;

let parsed;
try {
  parsed = JSON.parse(groqRes.choices[0].message.content);
} catch(e) {
  parsed = { intent:'general', team1:null, team2:null, player:null, collection:'matches', mongoFilter:{}, mongoLimit:5 };
}

return [{ json: {
  intent: parsed.intent || 'general',
  team1: parsed.team1 || null,
  team2: parsed.team2 || null,
  player: parsed.player || null,
  playerType: parsed.playerType || 'all',
  collection: parsed.collection || 'matches',
  mongoFilter: parsed.mongoFilter || {},
  mongoLimit: Math.min(parsed.mongoLimit || 10, 100),
  chatId: prev.chatId,
  username: prev.username,
  originalText: prev.originalText
}}];

const rows = $input.all().map(i => i.json);
const intentData = $('Parse Intent').first().json;

const clean = rows.map(d => { const x={...d}; delete x._id; return x; });

let contextSummary = '';

if (intentData.intent === 'stats' && clean.length > 0) {
  const totalRuns = clean.reduce((s,d) => s + (d.batsman_runs||0), 0);
  const balls = clean.length;
  const strikeRate = balls > 0 ? ((totalRuns/balls)*100).toFixed(2) : 0;
  const fours = clean.filter(d => d.batsman_runs===4).length;
  const sixes = clean.filter(d => d.batsman_runs===6).length;
  const dismissals = clean.filter(d => d.player_dismissed && d.player_dismissed===intentData.player).length;
  const avg = dismissals > 0 ? (totalRuns/dismissals).toFixed(2) : totalRuns;
  const matchIds = [...new Set(clean.map(d => d.matchId))];
  contextSummary = JSON.stringify({ player: intentData.player, innings: matchIds.length, totalRuns, balls, strikeRate, average: avg, fours, sixes, dismissals });
} else if (intentData.intent === 'headtohead' || intentData.intent === 'predict') {
  const wins = {};
  clean.forEach(m => { if (m.winner) wins[m.winner] = (wins[m.winner]||0)+1; });
  const venues = [...new Set(clean.map(m => m.venue))].slice(0,5);
  contextSummary = JSON.stringify({ totalMatches: clean.length, wins, venues, recentMatches: clean.slice(0,10) });
} else {
  contextSummary = JSON.stringify(clean.slice(0,15));
}

const systemPrompt = `You are CricketGPT — an expert IPL AI analyst. You have real IPL historical data.

Rules:
- Be passionate, data-driven, and engaging
- Use cricket emojis: 🏏🔥💥🎯
- Max 350 words
- Always cite specific numbers from the data provided

For FANTASY: Suggest 11 players with C and VC. Explain reasoning with stats.
For PREDICTION: Give win % for each team. Base on H2H record and key factors.
For STATS: Show runs, innings, avg, SR, 4s, 6s clearly formatted.
For H2H: Overall record, venue dominance, recent trend.
For GENERAL: Answer from data with trivia.

IPL Data:
${contextSummary}

Intent: ${intentData.intent} | Team1: ${intentData.team1||'N/A'} | Team2: ${intentData.team2||'N/A'} | Player: ${intentData.player||'N/A'}`;

return [{ json: {
  requestBody: JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: intentData.originalText }
    ],
    temperature: 0.75,
    max_tokens: 1000
  }),
  chatId: intentData.chatId
}}];

const groqRes = $input.first().json;
const prev = $('Build AI Request').first().json;

let text = '🏏 Sorry, could not generate a response. Try again!';
try {
  text = groqRes.choices[0].message.content;
  if (text.length > 4000) text = text.substring(0, 3997) + '...';
} catch(e) {}

return [{ json: { chatId: prev.chatId, text } }];
